pipe_server = '''#Requires -Version 7.4
#Requires -Modules RawrXD_PatternBridge

<#
.SYNOPSIS
    RawrXD IDE Pipe Server - Byte-Oriented Pattern Classification
    Uses RawrXD.PatternBridge.PatternEngine via Invoke-RawrXDClassification
#>

param(
    [string]$PipeName = "RawrXD_PatternBridge",
    [switch]$AsJob
)

$serverScript = {
    param($PipeName)
    
    Import-Module RawrXD_PatternBridge -Force
    
    $pipe = New-Object System.IO.Pipes.NamedPipeServerStream(
        $PipeName, 
        [System.IO.Pipes.PipeDirection]::InOut, 
        1, 
        [System.IO.Pipes.PipeTransmissionMode]::Message
    )
    
    Write-Host "[PipeServer] Started on $PipeName" -ForegroundColor Green
    
    while ($true) {
        $pipe.WaitForConnection()
        try {
            $reader = New-Object System.IO.BinaryReader($pipe)
            $writer = New-Object System.IO.StreamWriter($pipe)
            
            # Read command length (4 bytes)
            $cmdLenBytes = $reader.ReadBytes(4)
            if ($cmdLenBytes.Length -ne 4) { continue }
            $cmdLen = [BitConverter]::ToInt32($cmdLenBytes, 0)
            
            # Read command
            $cmdBytes = $reader.ReadBytes($cmdLen)
            $command = [Text.Encoding]::UTF8.GetString($cmdBytes)
            
            switch ($command) {
                "CLASSIFY" {
                    # Read data length (4 bytes)
                    $dataLenBytes = $reader.ReadBytes(4)
                    $dataLen = [BitConverter]::ToInt32($dataLenBytes, 0)
                    
                    # Read classification data
                    $data = $reader.ReadBytes($dataLen)
                    
                    # Classify using PatternEngine
                    $result = Invoke-RawrXDClassification -InputObject $data
                    
                    # Serialize result
                    $json = $result | ConvertTo-Json -Compress
                    $jsonBytes = [Text.Encoding]::UTF8.GetBytes($json)
                    
                    # Write response length + data
                    $lenBytes = [BitConverter]::GetBytes($jsonBytes.Length)
                    $pipe.Write($lenBytes, 0, 4)
                    $pipe.Write($jsonBytes, 0, $jsonBytes.Length)
                    $pipe.Flush()
                }
                
                "STATS" {
                    $stats = Get-RawrXDPatternStats
                    $json = $stats | ConvertTo-Json -Compress
                    $jsonBytes = [Text.Encoding]::UTF8.GetBytes($json)
                    $lenBytes = [BitConverter]::GetBytes($jsonBytes.Length)
                    $pipe.Write($lenBytes, 0, 4)
                    $pipe.Write($jsonBytes, 0, $jsonBytes.Length)
                    $pipe.Flush()
                }
                
                "PING" {
                    $pong = [Text.Encoding]::UTF8.GetBytes("PONG")
                    $lenBytes = [BitConverter]::GetBytes(4)
                    $pipe.Write($lenBytes, 0, 4)
                    $pipe.Write($pong, 0, 4)
                    $pipe.Flush()
                }
                
                "EXIT" { 
                    Write-Host "[PipeServer] Shutting down" -ForegroundColor Yellow
                    return 
                }
            }
        }
        catch {
            Write-Warning "[PipeServer] Error: $_"
        }
        finally {
            if ($pipe.IsConnected) { $pipe.Disconnect() }
        }
    }
}

if ($AsJob) {
    Start-Job -ScriptBlock $serverScript -ArgumentList $PipeName -Name "RawrXD-PipeServer"
    Write-Host "Pipe server started as background job. Monitor with: Get-Job -Name RawrXD-PipeServer" -ForegroundColor Green
} else {
    & $serverScript -PipeName $PipeName
}
'''

