// Win32 byte-oriented client for IDE integration

#pragma once
#include <windows.h>
#include <string>
#include <vector>
#include <json/json.h>

class RawrXDPipeClient {
private:
    HANDLE hPipe;
    bool connected;
    
public:
    RawrXDPipeClient() : hPipe(INVALID_HANDLE_VALUE), connected(false) {}
    
    ~RawrXDPipeClient() {
        Disconnect();
    }
    
    bool Connect(const char* pipeName = "RawrXD_PatternBridge", DWORD timeoutMs = 5000) {
        hPipe = CreateFileA(
            pipeName,
            GENERIC_READ | GENERIC_WRITE,
            0, NULL, OPEN_EXISTING, 0, NULL
        );
        
        if (hPipe == INVALID_HANDLE_VALUE) {
            // Try to start server
            WinExec("powershell -WindowStyle Hidden -Command \"Start-RawrXDPipeServer -AsJob\"", SW_HIDE);
            Sleep(1000);
            hPipe = CreateFileA(pipeName, GENERIC_READ | GENERIC_WRITE, 0, NULL, OPEN_EXISTING, 0, NULL);
        }
        
        if (hPipe != INVALID_HANDLE_VALUE) {
            DWORD mode = PIPE_READMODE_MESSAGE;
            SetNamedPipeHandleState(hPipe, &mode, NULL, NULL);
            connected = true;
        }
        
        return connected;
    }
    
    void Disconnect() {
        if (hPipe != INVALID_HANDLE_VALUE) {
            CloseHandle(hPipe);
            hPipe = INVALID_HANDLE_VALUE;
        }
        connected = false;
    }
    
    struct PatternResult {
        std::string type;
        double confidence;
        int lineNumber;
        int priority;
        bool success;
    };
    
    PatternResult ClassifyBuffer(const std::vector<BYTE>& data) {
        PatternResult result = {"Unknown", 0.0, 0, 0, false};
        
        if (!connected) return result;
        
        // Send CLASSIFY command
        std::string cmd = "CLASSIFY";
        SendCommand(cmd);
        
        // Send data length + data
        DWORD len = static_cast<DWORD>(data.size());
        WriteFile(hPipe, &len, 4, NULL, NULL);
        WriteFile(hPipe, data.data(), len, NULL, NULL);
        FlushFileBuffers(hPipe);
        
        // Read response
        std::string json = ReadResponse();
        
        // Parse JSON
        Json::Value root;
        Json::Reader reader;
        if (reader.parse(json, root)) {
            result.type = root["Pattern"].asString();
            result.confidence = root["Confidence"].asDouble();
            result.lineNumber = root["Line"].asInt();
            result.priority = root["Priority"].asInt();
            result.success = true;
        }
        
        return result;
    }
    
    PatternResult ClassifyFile(const char* filePath) {
        // Read file into buffer
        HANDLE hFile = CreateFileA(filePath, GENERIC_READ, FILE_SHARE_READ, NULL, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, NULL);
        if (hFile == INVALID_HANDLE_VALUE) return {"Error", 0.0, 0, 0, false};
        
        DWORD size = GetFileSize(hFile, NULL);
        std::vector<BYTE> buffer(size);
        DWORD read;
        ReadFile(hFile, buffer.data(), size, &read, NULL);
        CloseHandle(hFile);
        
        return ClassifyBuffer(buffer);
    }
    
    bool Ping() {
        if (!connected) return false;
        SendCommand("PING");
        std::string response = ReadResponse();
        return response == "PONG";
    }
    
private:
    void SendCommand(const std::string& cmd) {
        DWORD len = cmd.length();
        WriteFile(hPipe, &len, 4, NULL, NULL);
        WriteFile(hPipe, cmd.data(), len, NULL, NULL);
    }
    
    std::string ReadResponse() {
        DWORD len;
        ReadFile(hPipe, &len, 4, NULL, NULL);
        
        std::vector<char> buffer(len + 1);
        DWORD read;
        ReadFile(hPipe, buffer.data(), len, &read, NULL);
        buffer[len] = '\\0';
        
        return std::string(buffer.data());
    }
};

// Usage in your IDE:
// RawrXDPipeClient client;
